#include "surface_ops.h"
__declspec(dllexport) void run(void) { H radius,rect,color; cvm_pop(radius); cvm_pop(color); cvm_pop(rect); HWND w=surface_hwnd(); if(w){RECT r; surface_rect_from_h(rect,&r); int rr=(int)surface_scale_value((LONG)cvm_h_to_u64(radius)); HDC dc=GetDC(w); surface_apply_clip(dc); HBRUSH br=(HBRUSH)GetStockObject(NULL_BRUSH); HPEN pen=CreatePen(PS_SOLID,1,(COLORREF)cvm_h_to_u64(color)); HGDIOBJ old_br=SelectObject(dc,br); HGDIOBJ old_pen=SelectObject(dc,pen); RoundRect(dc,r.left,r.top,r.right,r.bottom,rr,rr); SelectObject(dc,old_pen); SelectObject(dc,old_br); DeleteObject(pen); ReleaseDC(w,dc);} cnext(); }
